          <div style={{ fontSize: 20, fontWeight: 700 }}>{bills.length}</div>
        </div>
        {canManage && <Btn onClick={() => setModal(true)}>Generate Bills</Btn>}
      </div>
      <Card title="Maintenance Bills">
        <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}>
