              <div style={{ fontSize: 12, color: '#64748b', marginBottom: 10, lineHeight: 1.5 }}>{a.description}</div>
              <div style={{ fontWeight: 700, color: '#10b981', marginBottom: 12, fontSize: 16 }}>₹{a.rent_amount}/hour</div>
              {canManage && (
                <div style={{ display: 'flex', gap: 8 }}>
                  <Btn variant="outline" sm onClick={() => handleEdit(a)}>Edit</Btn>
                  <Btn variant="danger" sm onClick={() => handleDelete(a.amenity_id)}>Delete</Btn>
                </div>
              )}
